-- Icon Kids — Identidade visual completa em todos os emails do sistema.
--
-- Padroniza os 7 templates de email com:
--   * Logo iCOM Kids (https://sistema.icomkids.com.br/brand/icomkids-logo.jpg)
--   * Linha de accent gradient (cores da paleta, variando por tema)
--   * Corpo branco com tipografia consistente
--   * Footer com paleta da marca + tagline "Diversao em movimento"
--
-- Templates atualizados (todos UPSERT - nao quebra mensagens em voo):
--   - email_session_welcome  (boas-vindas + termo)
--   - email_feedback_survey  (pesquisa pos-visita iCOM Motos)
--   - email_birthday_kid     (aniversario da crianca)
--   - email_post_visit_thanks (agradecimento pos-visita)
--   - email_subscription_renewed (assinatura renovada)
--   - email_term_signed      (termo assinado confirmacao)
--   - email_ticket_receipt   (recibo de ingresso comprado online)

-- ============================================================================
-- email_session_welcome — gradient azul -> ciano -> verde
-- ============================================================================
insert into public.message_templates (key, name, body) values (
  'email_session_welcome',
  '[Email] Boas-vindas + termo',
  E'<!doctype html>\n<html lang="pt-BR"><head><meta charset="UTF-8"/><title>Bem-vindo ao iCOM Kids</title></head>\n<body style="margin:0;padding:0;background:#f6f7fb;font-family:-apple-system,BlinkMacSystemFont,\\"Segoe UI\\",Roboto,Arial,sans-serif;color:#0f172a;">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:32px 16px;"><tr><td align="center">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:18px;overflow:hidden;box-shadow:0 6px 24px rgba(15,23,42,0.08);">\n<tr><td style="padding:32px 28px 16px;text-align:center;background:#ffffff;"><img src="https://sistema.icomkids.com.br/brand/icomkids-logo.jpg" alt="iCOM Kids" width="140" height="auto" style="display:block;margin:0 auto;max-width:140px;height:auto;border:0;"></td></tr>\n<tr><td style="background:linear-gradient(90deg,#1E78DC 0%,#3CB4E0 50%,#A6CD3F 100%);height:5px;line-height:5px;font-size:0;">&nbsp;</td></tr>\n<tr><td style="padding:32px 28px;">\n<h1 style="margin:0 0 8px;font-size:24px;font-weight:900;line-height:1.2;color:#0f172a;">Bem-vindo, {{nome}}! 🛝</h1>\n<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">A <strong>{{crianca}}</strong> chegou agora pra brincar no iCOM Kids. Sessao de <strong>{{tempo}} minutos</strong> rodando!</p>\n<p style="margin:0 0 24px;font-size:16px;line-height:1.5;"><strong>Antes da diversao começar:</strong> leia e marque que aceita nosso termo de responsabilidade. Leva 1 minutinho no celular.</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:0 auto;"><tr><td align="center" style="background:#1E78DC;border-radius:999px;"><a href="{{link}}" style="display:inline-block;padding:14px 36px;color:#ffffff;font-weight:700;font-size:15px;text-decoration:none;letter-spacing:0.5px;">Aceitar o termo →</a></td></tr></table>\n<p style="margin:24px 0 0;font-size:13px;line-height:1.5;color:#64748b;text-align:center;">Se o botao nao funcionar, copie e cole no navegador:<br/><a href="{{link}}" style="color:#1E78DC;word-break:break-all;">{{link}}</a></p>\n</td></tr>\n<tr><td style="padding:0 28px;"><hr style="border:none;border-top:1px solid #e2e8f0;margin:0;"/></td></tr>\n<tr><td style="padding:20px 28px 24px;text-align:center;"><p style="margin:0;color:#94a3b8;font-size:11px;letter-spacing:3px;text-transform:uppercase;font-weight:700;">Diversao em movimento</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:12px auto 0;"><tr><td style="width:10px;height:10px;background:#1E78DC;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#3CB4E0;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#F39230;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#EA4D8E;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#A6CD3F;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td></tr></table>\n<p style="margin:14px 0 0;color:#64748b;font-size:11px;">iCOM Kids · contato@icomkids.com.br</p></td></tr>\n</table></td></tr></table></body></html>'
) on conflict (key) do update set body=excluded.body, name=excluded.name;

-- ============================================================================
-- email_feedback_survey — gradient azul -> roxo -> rosa
-- ============================================================================
insert into public.message_templates (key, name, body) values (
  'email_feedback_survey',
  '[Email] Pesquisa pos-visita',
  E'<!doctype html>\n<html lang="pt-BR"><head><meta charset="UTF-8"/><title>Obrigado pela visita, {{nome}}!</title></head>\n<body style="margin:0;padding:0;background:#f6f7fb;font-family:-apple-system,BlinkMacSystemFont,\\"Segoe UI\\",Roboto,Arial,sans-serif;color:#0f172a;">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:32px 16px;"><tr><td align="center">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:18px;overflow:hidden;box-shadow:0 6px 24px rgba(15,23,42,0.08);">\n<tr><td style="padding:32px 28px 16px;text-align:center;background:#ffffff;"><img src="https://sistema.icomkids.com.br/brand/icomkids-logo.jpg" alt="iCOM Kids" width="140" height="auto" style="display:block;margin:0 auto;max-width:140px;height:auto;border:0;"></td></tr>\n<tr><td style="background:linear-gradient(90deg,#1E78DC 0%,#7B36BF 50%,#EA4D8E 100%);height:5px;line-height:5px;font-size:0;">&nbsp;</td></tr>\n<tr><td style="padding:32px 28px;">\n<h1 style="margin:0 0 8px;font-size:24px;font-weight:900;line-height:1.2;color:#0f172a;">Obrigado pela visita, {{nome}}! 💙</h1>\n<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">A visita de <strong>{{crianca}}</strong> chegou ao fim. A gente espera que tenha sido uma <strong>diversao em movimento</strong> 🛝🎈</p>\n<p style="margin:0 0 24px;font-size:16px;line-height:1.5;">Sua opiniao e o que faz a gente melhorar. <strong>Da pra responder em 1 minuto?</strong></p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:0 auto;"><tr><td align="center" style="background:#1E78DC;border-radius:999px;"><a href="{{link}}" style="display:inline-block;padding:14px 36px;color:#ffffff;font-weight:700;font-size:15px;text-decoration:none;letter-spacing:0.5px;">Avaliar a experiencia →</a></td></tr></table>\n<p style="margin:24px 0 0;font-size:13px;line-height:1.5;color:#64748b;text-align:center;">Se o botao nao funcionar, copie e cole no navegador:<br/><a href="{{link}}" style="color:#1E78DC;word-break:break-all;">{{link}}</a></p>\n</td></tr>\n<tr><td style="padding:0 28px;"><hr style="border:none;border-top:1px solid #e2e8f0;margin:0;"/></td></tr>\n<tr><td style="padding:20px 28px 24px;text-align:center;"><p style="margin:0;color:#94a3b8;font-size:11px;letter-spacing:3px;text-transform:uppercase;font-weight:700;">Diversao em movimento</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:12px auto 0;"><tr><td style="width:10px;height:10px;background:#1E78DC;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#3CB4E0;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#F39230;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#EA4D8E;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#A6CD3F;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td></tr></table>\n<p style="margin:14px 0 0;color:#64748b;font-size:11px;">iCOM Kids · contato@icomkids.com.br</p></td></tr>\n</table></td></tr></table></body></html>'
) on conflict (key) do update set body=excluded.body, name=excluded.name;

-- ============================================================================
-- email_birthday_kid — gradient amarelo -> laranja -> rosa
-- ============================================================================
insert into public.message_templates (key, name, body) values (
  'email_birthday_kid',
  '[Email] Aniversario da crianca',
  E'<!doctype html>\n<html lang="pt-BR"><head><meta charset="UTF-8"/><title>Feliz aniversario, {{crianca}}!</title></head>\n<body style="margin:0;padding:0;background:#f6f7fb;font-family:-apple-system,BlinkMacSystemFont,\\"Segoe UI\\",Roboto,Arial,sans-serif;color:#0f172a;">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:32px 16px;"><tr><td align="center">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:18px;overflow:hidden;box-shadow:0 6px 24px rgba(15,23,42,0.08);">\n<tr><td style="padding:32px 28px 16px;text-align:center;background:#ffffff;"><img src="https://sistema.icomkids.com.br/brand/icomkids-logo.jpg" alt="iCOM Kids" width="140" height="auto" style="display:block;margin:0 auto;max-width:140px;height:auto;border:0;"></td></tr>\n<tr><td style="background:linear-gradient(90deg,#F4B73F 0%,#F39230 50%,#EA4D8E 100%);height:5px;line-height:5px;font-size:0;">&nbsp;</td></tr>\n<tr><td style="padding:32px 28px;text-align:center;">\n<p style="margin:0;font-size:48px;line-height:1;">🎂🎉</p>\n<h1 style="margin:16px 0 8px;font-size:26px;font-weight:900;line-height:1.2;color:#0f172a;">Feliz aniversario, {{crianca}}!</h1>\n<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">Oi {{nome}}, hoje e um dia especial!</p>\n<p style="margin:0 0 24px;font-size:16px;line-height:1.5;">O time do iCOM Kids deseja muita alegria pra <strong>{{crianca}}</strong>. Que tal comemorar com a gente? Brincadeira, alegria e diversao em movimento esperam por voces 🛝</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:0 auto;"><tr><td align="center" style="background:#EA4D8E;border-radius:999px;"><a href="https://wa.me/5512997423129" style="display:inline-block;padding:14px 32px;color:#ffffff;font-weight:700;font-size:15px;text-decoration:none;letter-spacing:0.5px;">Falar com a gente</a></td></tr></table>\n</td></tr>\n<tr><td style="padding:0 28px;"><hr style="border:none;border-top:1px solid #e2e8f0;margin:0;"/></td></tr>\n<tr><td style="padding:20px 28px 24px;text-align:center;"><p style="margin:0;color:#94a3b8;font-size:11px;letter-spacing:3px;text-transform:uppercase;font-weight:700;">Diversao em movimento</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:12px auto 0;"><tr><td style="width:10px;height:10px;background:#1E78DC;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#3CB4E0;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#F39230;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#EA4D8E;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#A6CD3F;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td></tr></table>\n<p style="margin:14px 0 0;color:#64748b;font-size:11px;">iCOM Kids · contato@icomkids.com.br</p></td></tr>\n</table></td></tr></table></body></html>'
) on conflict (key) do update set body=excluded.body, name=excluded.name;

