insert into public.message_templates (key, name, body) values (
  'email_term_signed',
  '[Email] Termo de responsabilidade aceito',
  E'<!doctype html>\n<html lang="pt-BR"><head><meta charset="UTF-8"/><title>Termo recebido, {{nome}}!</title></head>\n<body style="margin:0;padding:0;background:#f6f7fb;font-family:-apple-system,BlinkMacSystemFont,\\"Segoe UI\\",Roboto,Arial,sans-serif;color:#0f172a;">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:32px 16px;"><tr><td align="center">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:18px;overflow:hidden;box-shadow:0 6px 24px rgba(15,23,42,0.08);">\n<tr><td style="padding:32px 28px 16px;text-align:center;background:#ffffff;"><img src="https://sistema.icomkids.com.br/brand/icomkids-logo.jpg" alt="iCOM Kids" width="140" height="auto" style="display:block;margin:0 auto;max-width:140px;height:auto;border:0;"></td></tr>\n<tr><td style="background:linear-gradient(90deg,#A6CD3F 0%,#1E78DC 100%);height:5px;line-height:5px;font-size:0;">&nbsp;</td></tr>\n<tr><td style="padding:32px 28px;text-align:center;">\n<p style="margin:0;font-size:48px;line-height:1;">✅</p>\n<h1 style="margin:16px 0 8px;font-size:24px;font-weight:900;line-height:1.2;">Termo recebido, {{nome}}!</h1>\n<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">Guardamos seu aceite com seguranca. Tudo certo pra diversao.</p>\n<p style="margin:0;font-size:16px;line-height:1.5;color:#0f172a;">Boa visita ao iCOM Kids 💙</p>\n</td></tr>\n<tr><td style="padding:0 28px;"><hr style="border:none;border-top:1px solid #e2e8f0;margin:0;"/></td></tr>\n<tr><td style="padding:20px 28px 24px;text-align:center;"><p style="margin:0;color:#94a3b8;font-size:11px;letter-spacing:3px;text-transform:uppercase;font-weight:700;">Diversao em movimento</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:12px auto 0;"><tr><td style="width:10px;height:10px;background:#1E78DC;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#3CB4E0;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#F39230;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#EA4D8E;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#A6CD3F;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td></tr></table>\n<p style="margin:14px 0 0;color:#64748b;font-size:11px;">iCOM Kids · contato@icomkids.com.br</p></td></tr>\n</table></td></tr></table></body></html>'
) on conflict (key) do update set body=excluded.body, name=excluded.name;

-- ============================================================================
-- email_ticket_receipt — gradient azul -> rosa
-- ============================================================================
insert into public.message_templates (key, name, body) values (
  'email_ticket_receipt',
  '[Email] Recibo de compra de ingresso',
  E'<!doctype html>\n<html lang="pt-BR"><head><meta charset="UTF-8"/><title>Obrigado pela compra, {{nome}}!</title></head>\n<body style="margin:0;padding:0;background:#f6f7fb;font-family:-apple-system,BlinkMacSystemFont,\\"Segoe UI\\",Roboto,Arial,sans-serif;color:#0f172a;">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:32px 16px;"><tr><td align="center">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:18px;overflow:hidden;box-shadow:0 6px 24px rgba(15,23,42,0.08);">\n<tr><td style="padding:32px 28px 16px;text-align:center;background:#ffffff;"><img src="https://sistema.icomkids.com.br/brand/icomkids-logo.jpg" alt="iCOM Kids" width="140" height="auto" style="display:block;margin:0 auto;max-width:140px;height:auto;border:0;"></td></tr>\n<tr><td style="background:linear-gradient(90deg,#1E78DC 0%,#EA4D8E 100%);height:5px;line-height:5px;font-size:0;">&nbsp;</td></tr>\n<tr><td style="padding:32px 28px;">\n<h1 style="margin:0 0 8px;font-size:24px;font-weight:900;line-height:1.2;">Obrigado, {{nome}}! 💙</h1>\n<p style="margin:0 0 16px;font-size:16px;line-height:1.5;">Recebemos seu pagamento. Tudo certo pra brincar!</p>\n<table role="presentation" cellpadding="0" cellspacing="0" style="margin:24px 0;background:#1E78DC10;border-radius:12px;width:100%;"><tr><td style="padding:20px;"><p style="margin:0;font-size:11px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#64748b;">Pacote</p><p style="margin:4px 0 16px;font-size:18px;font-weight:800;color:#0f172a;">{{pacote}}</p><p style="margin:0;font-size:11px;font-weight:700;letter-spacing:2px;text-transform:uppercase;color:#64748b;">Valor pago</p><p style="margin:4px 0 0;font-size:22px;font-weight:900;color:#1E78DC;">{{valor}}</p></td></tr></table>\n<p style="margin:0 0 24px;font-size:16px;line-height:1.5;text-align:center;">Apresente o QR Code abaixo na entrada do iCOM Kids:</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:0 auto;"><tr><td align="center" style="background:#1E78DC;border-radius:999px;"><a href="{{link}}" style="display:inline-block;padding:14px 36px;color:#ffffff;font-weight:700;font-size:15px;text-decoration:none;letter-spacing:0.5px;">Ver QR Code →</a></td></tr></table>\n<p style="margin:24px 0 0;font-size:13px;line-height:1.5;color:#64748b;text-align:center;">Ate ja!</p>\n</td></tr>\n<tr><td style="padding:0 28px;"><hr style="border:none;border-top:1px solid #e2e8f0;margin:0;"/></td></tr>\n<tr><td style="padding:20px 28px 24px;text-align:center;"><p style="margin:0;color:#94a3b8;font-size:11px;letter-spacing:3px;text-transform:uppercase;font-weight:700;">Diversao em movimento</p>\n<table role="presentation" cellpadding="0" cellspacing="0" align="center" style="margin:12px auto 0;"><tr><td style="width:10px;height:10px;background:#1E78DC;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#3CB4E0;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#F39230;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#EA4D8E;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td><td style="width:8px;"></td><td style="width:10px;height:10px;background:#A6CD3F;border-radius:50%;line-height:10px;font-size:0;">&nbsp;</td></tr></table>\n<p style="margin:14px 0 0;color:#64748b;font-size:11px;">iCOM Kids · contato@icomkids.com.br</p></td></tr>\n</table></td></tr></table></body></html>'
) on conflict (key) do update set body=excluded.body, name=excluded.name;
